INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$AI Avatar Video Generation$q$, $q$Convert scripts into narrated videos using 160+ realistic AI avatars with natural lip-sync, facial expressions, and gestures.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Multilingual Narration & Dubbing$q$, $q$Translate and dub avatar narration, on-screen text, and interactive elements together, with voice cloning available in roughly 29 languages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Interactive Learning Elements$q$, $q$Add branching decision-tree scenarios and multiple-choice quizzes directly inside videos to boost learner engagement and check comprehension.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$SCORM Export for LMS$q$, $q$Export finished videos as SCORM packages that report completion and quiz scores inside most learning management systems.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Document & Slide Import$q$, $q$Turn existing PowerPoint decks, PDFs, or Word documents into a video draft with avatar narration automatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Brand Kit & Screen Recorder$q$, $q$Apply custom logos, fonts, and colors across videos and templates, and record and embed screen captures inside the editor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$API & Zapier Automation$q$, $q$Generate videos programmatically with personalization variables, or trigger generation from 5,000+ apps via Zapier.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Genuine free tier for individuals exploring AI video before paying$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$No filming, actors, or studio production required to update training content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Strong e-learning feature set (SCORM export, quizzes, branching scenarios) that many general AI video tools lack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Fast localization of a single script into many languages without re-shooting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$AI avatars can still look synthetic under close inspection, especially in premium/emotive delivery$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$SCORM export and watermark removal are locked behind paid plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Limited native integrations outside of Zapier and the API$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Minute-based usage caps on lower tiers can get expensive for high-volume video production$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Is Colossyan free to use?$q$, $q$Yes, the Starter plan is free and includes a limited number of avatar-narration minutes per month, though SCORM export and watermark removal require a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Does Colossyan support multiple languages?$q$, $q$Yes, avatar narration, on-screen text, and interactive elements can be translated and dubbed together, with voice cloning supported in around 29 languages.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Can Colossyan videos be uploaded to a learning management system?$q$, $q$Yes, Professional and Enterprise plans can export finished videos as SCORM packages compatible with most LMS platforms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Who is Colossyan built for?$q$, $q$It is aimed primarily at corporate learning and development, HR, and internal communications teams rather than consumer video creators.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Does Colossyan have an API?$q$, $q$Yes, an API is available for programmatic, large-scale video generation with the same feature set as the visual editor, and it also connects to thousands of apps via Zapier.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Compliance and safety training$q$, $q$Convert policy documents into narrated training videos with quizzes to track employee completion.$q$, $q$L&D and HR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Multilingual onboarding$q$, $q$Localize a single onboarding script into many languages without re-filming for each region.$q$, $q$Global enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Sales enablement content$q$, $q$Turn product one-pagers or slide decks into short avatar-led explainer videos for reps and prospects.$q$, $q$Sales enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Starter$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["Limited AI avatar-narration minutes per month","15 custom avatars + 3 voices","Up to 10 interactive videos/month","Auto-translations","Unlimited course creation","No SCORM export"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Professional$q$, $q$$59/month$q$, $q$Annual (monthly billing also available)$q$, NULL, $q$["More avatar minutes across standard and NEO2 avatar tiers","20 custom avatars + 5 voices","Unlimited watermark-free MP4 downloads","SCORM exports","AI image generation","Up to 3 editors"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Unlimited standard avatar minutes, custom NEO2 minutes","Unlimited custom/branded avatars and voices","Unlimited SCORM exports","SSO/SAML and data residency","Dedicated customer success manager","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Colossyan is an AI video generator focused on corporate training and learning content. Instead of filming with a camera and a human presenter, users write or paste a script and Colossyan renders a video with an AI avatar that speaks the script with synchronized lip movement, expressions, and gestures.$q$, $q$Founded in 2020 in Budapest by CEO Dominik Mate Kovacs, the company now has offices in Budapest, New York, and London and serves tens of thousands of business accounts, primarily learning and development, HR, and internal communications teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform includes over 160 AI avatars and 170+ voices, custom voice cloning, a Brand Kit for consistent visual branding, and a built-in screen recorder for mixing live screen capture with avatar narration.$q$, $q$E-learning-specific tools set Colossyan apart from general AI video generators: interactive quizzes, branching scenarios, and SCORM export so completed videos can plug directly into a company's LMS and report learner progress and scores.$q$, $q$A document-to-video feature converts existing PowerPoint files, PDFs, or Word documents into a video draft automatically, and an API with Zapier connectivity lets teams trigger video generation from CRM updates, form submissions, or other workflow events.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Colossyan follows a freemium model. The Starter plan is free and covers a limited number of avatar-narration minutes per month with no SCORM export. The Professional plan is $59/month billed annually and adds more avatar minutes, watermark-free downloads, SCORM export, AI image generation, and up to three editor seats.$q$, $q$Enterprise pricing is custom and adds unlimited video minutes, unlimited SCORM exports, branded or custom studio avatars, SSO/SAML, data residency controls, and a dedicated customer success manager for larger, security-conscious organizations.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', $q$localization$q$, $q$Multilingual and Localization Capabilities$q$, 2, ARRAY[$q$Colossyan is built around localizing a single piece of training content into many languages at once: avatar narration, on-screen text, and interactive elements can all be translated and dubbed together within the same editor, and voice cloning supports roughly 29 languages.$q$, $q$This makes it a common choice for multinational companies that need to roll out the same compliance, safety, or onboarding training across regional offices without re-filming or hiring local voice talent for each language.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
