INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Native AI Sidebar Assistant$q$, $q$An AI agent lives in the browser sidebar, aware of the current tab and able to answer questions, summarize, or take action without switching apps.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Cited Answer Engine Built In$q$, $q$Perplexity's search and cited-answer capabilities are available on every page, not just a separate search tab.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Cross-Tab Research$q$, $q$The assistant retains context across multiple open tabs to help with comparison shopping, research, and multi-step tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Background Agent (Max)$q$, $q$Max subscribers get a background assistant that can handle multi-step tasks like booking or emailing with reduced manual supervision.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Built-In Ad Blocker$q$, $q$Comet includes native ad blocking without requiring a separate extension.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Cross-Platform Availability$q$, $q$Available free on Windows, macOS, Android, and iOS, with voice mode on mobile.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Free to use on all major desktop and mobile platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$AI assistant is deeply integrated rather than a bolt-on extension$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Backed by Perplexity's well-regarded cited-answer search engine$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Rapid platform expansion (Android and iOS added within a year of launch)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Independent researchers have found prompt-injection vulnerabilities that can hijack the agent's actions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Granting the agent access to email, calendar, and password manager sessions raises real data-exposure risk$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Most advanced agentic features are reserved for the $200/month Max plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$As a newer Chromium-based browser, extension and enterprise-management ecosystem is less mature than Chrome or Edge$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Is Comet free?$q$, $q$Yes, Comet is free to download and use on Windows, macOS, Android, and iOS. Perplexity Max ($200/month) unlocks more advanced agentic features and top-tier model access inside the browser.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Is Comet the same as Comet ML?$q$, $q$No. Comet here refers to Perplexity AI's agentic web browser. Comet ML is a separate, unrelated company that makes machine learning experiment-tracking software.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$What platforms is Comet available on?$q$, $q$Comet launched on Windows and macOS in 2025, followed by Android in November 2025 and iOS/iPadOS in March 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Is Comet safe to use?$q$, $q$Perplexity has published security documentation and patched several issues, but independent researchers have demonstrated prompt-injection attacks against Comet's agent, so users should be cautious about granting it access to sensitive accounts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$What is Comet Plus?$q$, $q$Comet Plus is a separate $5/month add-on that provides AI-enhanced access to publisher news content, distinct from the free Comet browser itself.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$AI-assisted web research$q$, $q$Ask questions about the current page or research a topic across multiple open tabs without switching to a separate search tool.$q$, $q$Students, researchers, and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Everyday task automation$q$, $q$Have the assistant summarize long articles, draft email replies, or compare options across several tabs while browsing.$q$, $q$General consumers and professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Agentic multi-step workflows$q$, $q$Max subscribers can delegate multi-step tasks like research compilation or booking to the background assistant.$q$, $q$Power users on Perplexity Max$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Chromium-based browsing","Sidebar AI assistant","Perplexity answer engine","Built-in ad blocker","Available on Windows, macOS, Android, iOS"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Comet Plus$q$, $q$$5/month$q$, $q$Monthly$q$, NULL, $q$["AI-enhanced access to publisher news content","Add-on to the free Comet browser"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$Perplexity Max$q$, $q$$200/month$q$, $q$Monthly$q$, NULL, $q$["Advanced agentic browsing features","Background assistant for multi-step tasks","Access to top-tier models for agent tasks","Priority access to new Comet features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Comet is Perplexity AI's web browser, built on Chromium, with an AI agent embedded natively in the sidebar rather than offered as a separate extension. The agent is aware of the page a user is viewing, can answer questions about it, and can take actions like summarizing content, comparing options across tabs, or completing simple multi-step tasks.$q$, $q$Perplexity, the company behind Comet, was founded in 2022 by Aravind Srinivas, Denis Yarats, Johnny Ho, and Andy Konwinski and is headquartered in San Francisco. Comet launched in mid-2025 as a paid, invite-limited product before becoming free worldwide later that year.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Comet integrates Perplexity's cited-answer search engine directly into browsing, so users can ask questions about a page or the web generally without switching tools. A sidebar assistant retains context across tabs and can be asked to summarize, compare, or research across multiple open pages.$q$, $q$For subscribers on Perplexity's Max plan, Comet includes a background assistant capable of running multi-step tasks (such as research or booking workflows) with less step-by-step supervision, along with access to more capable underlying models for agentic tasks.$q$, $q$The browser also includes a built-in ad blocker and voice mode on mobile, and is available across Windows, macOS, Android, and iOS as of 2026.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Comet itself is free to download and use on all supported platforms. Perplexity monetizes the surrounding ecosystem rather than the browser directly: a $5/month Comet Plus add-on provides AI-enhanced access to publisher news content, and Perplexity's $200/month Max subscription unlocks the most advanced agentic features and top-tier model access inside Comet.$q$, $q$There is no separate business or team pricing tier specific to Comet at this time; it is bundled with Perplexity's consumer subscription plans.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', $q$security-considerations$q$, $q$Security and Privacy Considerations$q$, 2, ARRAY[$q$Because Comet's agent can act on a user's behalf inside authenticated sessions (email, calendars, password managers, and other logged-in services), security researchers have identified prompt-injection vulnerabilities that could let a malicious webpage, link, or calendar invite manipulate the agent into leaking data or taking unintended actions.$q$, $q$Perplexity has responded with patches and a published security FAQ, but independent security firms continue to flag agentic browsing as an emerging risk category, and users handling sensitive accounts should weigh convenience against the broader access an AI browser agent requires.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
