INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1e51b23-11d5-4a32-91ce-ccf878a2484a', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Google Reader-Style Interface$q$, $q$Folder-based subscription management, unread counts, and keyboard shortcuts recreate the classic Google Reader workflow.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Self-Hosting via Docker$q$, $q$Deploy your own private instance with Docker, backed by H2, PostgreSQL, MySQL, or MariaDB.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Free Hosted Public Instance$q$, $q$Use the ad-free, tracking-free public instance at commafeed.com without running your own server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$OPML Import/Export$q$, $q$Move subscriptions in and out of CommaFeed easily when switching from or to other feed readers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$REST API with Fever Compatibility$q$, $q$A documented REST API, including Fever-API compatibility, lets third-party RSS client apps connect to CommaFeed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Multi-User Support$q$, $q$Multiple user accounts let each person curate and follow their own independent list of feeds.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Deep Customization$q$, $q$Custom CSS and JavaScript, four layout options, light/dark themes, and a UI translated into 25+ languages.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Completely free, whether self-hosted or using the public instance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Open-source (Apache-2.0) with an active GitHub community and regular releases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$No ads or tracking on the official hosted instance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Lightweight Java/Quarkus backend with fast startup and low resource usage for self-hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$No AI summarization or content-discovery features found in some modern readers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Interface is intentionally minimal and dated compared to commercial readers like Feedly or Inoreader$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Self-hosting requires basic server/Docker familiarity to get full control over your data$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Maintained largely by a small open-source community rather than a funded company$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Is CommaFeed really free?$q$, $q$Yes. CommaFeed is free and open-source under the Apache-2.0 license, both as a self-hosted deployment and via the free public instance at commafeed.com.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Can I self-host CommaFeed?$q$, $q$Yes, CommaFeed is designed to be self-hosted, with official Docker images and support for H2, PostgreSQL, MySQL, and MariaDB databases.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Does CommaFeed have a mobile app?$q$, $q$CommaFeed does not have dedicated native mobile apps, but its web interface is fully responsive and works well on mobile browsers, and it supports Fever-API-compatible third-party RSS apps.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$How is CommaFeed different from Feedly or Inoreader?$q$, $q$CommaFeed is free and open-source with no ad-supported or premium tiers, aimed at users who want a lightweight, self-hostable, Google-Reader-style reader rather than a commercial platform with AI features and paid plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Is CommaFeed still maintained?$q$, $q$Yes, CommaFeed remains an actively maintained open-source project on GitHub with regular releases.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Privacy-focused feed reading$q$, $q$Self-host CommaFeed to keep full control of reading data instead of relying on a third-party commercial reader.$q$, $q$Privacy-conscious individuals and homelab users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Team or organizational news monitoring$q$, $q$Run a shared self-hosted instance with multiple user accounts so different team members can track their own feed subscriptions.$q$, $q$Small teams and organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Lightweight Google Reader replacement$q$, $q$Use the free hosted instance for a familiar, ad-free, keyboard-driven RSS reading experience.$q$, $q$Former Google Reader users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$Free / Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Free public hosted instance at commafeed.com","Self-hosted deployment via Docker","Unlimited feeds and folders","REST API access","Open-source, Apache-2.0 licensed"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CommaFeed is an open-source RSS/Atom feed reader designed to recreate the folder-based, keyboard-friendly reading experience of the discontinued Google Reader. It launched in May 2013 in direct response to Google Reader's shutdown announcement.$q$, $q$The project is free, ad-free, and available either through a hosted public instance at commafeed.com or as self-hosted software that anyone can run on their own server or homelab.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CommaFeed supports OPML import/export for migrating subscriptions, a REST API with Fever-API compatibility for third-party clients, keyboard shortcuts for nearly every action, and four selectable layouts with light and dark themes.$q$, $q$The interface is fully responsive on mobile and desktop, supports push notifications for new articles, right-to-left language feeds, and a UI translated into more than 25 languages, with custom CSS/JavaScript support for advanced personalization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CommaFeed is entirely free. The public hosted instance at commafeed.com has no ads or tracking, and the self-hosted version, distributed via Docker images, is free to deploy on your own infrastructure under the Apache-2.0 open-source license.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', $q$self-hosting$q$, $q$Self-Hosting and Technology$q$, 2, ARRAY[$q$The backend is built with Java on the Quarkus framework for fast startup and low memory footprint, while the frontend uses React and TypeScript. It supports H2 for lightweight setups and PostgreSQL, MySQL, or MariaDB for larger self-hosted deployments.$q$, $q$Self-hosting is the standard route for users who want full control over their reading data and infrastructure, and Docker images are published and updated regularly on Docker Hub to simplify deployment.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3476f2a-8c51-4b81-9db1-f7d876d3be6b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$30+ Data Source Integrations$q$, $q$Capture signals from Slack, Discord, GitHub, Reddit, LinkedIn, Twitter/X, Stack Overflow, DEV, Segment, and more in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Identity Resolution$q$, $q$Connect scattered activity across channels back to real people and accounts for a unified engagement view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$RoomieAI Research Agent$q$, $q$An AI agent that researches accounts and contacts and produces summarized, actionable insights for GTM teams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Prospector$q$, $q$AI-assisted account and contact discovery to find new prospects that match existing buying-signal patterns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$CRM Sync$q$, $q$Push enriched contact and signal data into Salesforce and HubSpot so reps can act without leaving their CRM.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Unlimited Alerts, Workflows & Segments$q$, $q$Configure real-time alerts and automated workflows triggered by specific buying signals, with no limit on how many are set up.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Very broad set of native data source integrations (30+) compared to most GTM intelligence tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$AI agent features (RoomieAI, Prospector) reduce manual research time for sales and marketing teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Strong fit for developer- and community-led GTM motions where GitHub/Slack/Discord activity predicts buying intent$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Backed by significant funding ($104.9M+) and a pending Zoom acquisition suggesting continued investment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$No free tier; entry pricing starts at $2,500/month billed annually$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Advanced and Enterprise pricing is not public and requires a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Pending Zoom acquisition creates some uncertainty about the product's long-term roadmap and standalone positioning$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Best suited to companies with an active community or developer presence; less value for traditional sales-only motions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Is Common Room being acquired?$q$, $q$Yes. Zoom announced a definitive agreement to acquire Common Room in July 2026 to add buyer intelligence to its AI revenue platform. Financial terms were not disclosed, and the deal was expected to close within weeks of the announcement.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Is Common Room the same company as Commsor?$q$, $q$No, they are separate companies. Common Room and Commsor operate in adjacent categories (customer intelligence and community/GTM signals, respectively) and have historically been listed as competitors or alternatives, but there has been no merger between them.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$What integrations does Common Room support?$q$, $q$Common Room connects to more than 30 sources including Slack, Discord, GitHub, Reddit, LinkedIn, Twitter/X, Stack Overflow, DEV, Segment, Salesforce, and HubSpot.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Does Common Room have a free plan?$q$, $q$No, Common Room does not offer a free tier. The lowest published tier, Essential, starts at $2,500/month billed annually.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Who uses Common Room?$q$, $q$It's primarily used by go-to-market, sales, marketing, community, and product teams at B2B SaaS companies, especially those with developer- or community-driven growth motions.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Community-led sales signals$q$, $q$Surface which community members (Slack, Discord, GitHub) show buying intent and route them to sales at the right moment.$q$, $q$Developer-tool and open-source-adjacent companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Unified account intelligence$q$, $q$Combine engagement data from dozens of channels into a single account view for account executives and CSMs.$q$, $q$B2B SaaS sales and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$AI-assisted prospecting$q$, $q$Use Prospector and RoomieAI to identify and research new accounts that match existing high-intent signal patterns.$q$, $q$Outbound sales and demand generation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Essential$q$, $q$$2,500/month$q$, $q$Annual$q$, NULL, $q$["5 seats","Up to 100,000 contacts","5,000 RoomieAI research credits/month","2,500 Prospector credits/month","Unlimited alerts, workflows, and segments","Shared customer success manager"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Advanced$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["15 seats","Up to 250,000 contacts","7,500 RoomieAI research credits/month","7,500 Prospector credits/month","Dedicated customer success manager"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["30 seats","Up to 750,000 contacts","10,000 RoomieAI research credits/month","15,000 Prospector credits/month","Comprehensive integrations","Dedicated customer success manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Common Room is a customer intelligence platform that pulls together buying signals from dozens of sources — community platforms, developer tools, social channels, and CRM data — into a single, person-level view for go-to-market teams. It was founded in 2020 in Seattle by Francis Luu, Linda Lian, Tom Kleinpeter, and Viraj Mody.$q$, $q$In July 2026, Zoom announced a definitive agreement to acquire Common Room to add upstream buyer intelligence to its AI revenue platform, a deal expected to close within weeks of the announcement.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform connects to 30+ sources including Slack, Discord, GitHub, Reddit, LinkedIn, Twitter/X, Stack Overflow, and DEV, using identity resolution to tie scattered activity back to real accounts and people.$q$, $q$AI agent features — RoomieAI for research and Prospector for account/contact discovery — automate much of the manual digging sales and marketing teams previously did manually, and unlimited alerts, workflows, and segments let teams act on signals as they happen.$q$, $q$Enriched signal and contact data syncs into Salesforce and HubSpot so reps can act inside the CRM tools they already use.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Common Room publishes one self-serve-adjacent tier, Essential, at $2,500/month billed annually for 5 seats and up to 100,000 contacts. Advanced and Enterprise tiers scale seats, contacts, and AI credit allotments and require a custom quote from sales.$q$, $q$There is no free tier, positioning Common Room as a mid-market-to-enterprise tool rather than a self-serve product for small teams.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', $q$acquisition-status$q$, $q$Zoom Acquisition$q$, 2, ARRAY[$q$In July 2026, Zoom entered into a definitive agreement to acquire Common Room, folding its buyer-intelligence capabilities into Zoom's broader AI revenue platform. Financial terms were not disclosed, and the deal was expected to close within weeks, subject to customary closing conditions.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba720441-8cc7-4c09-b643-008d959f36c9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Network Mapping$q$, $q$Identify warm introduction paths to target accounts through investors, advisors, partners, alumni, and existing customers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Referral Program Automation$q$, $q$Run scalable B2B referral programs with deal registration and tracked payouts for partners and advisors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Signal-Based Alerts$q$, $q$Get notified when a target account raises funding, makes a senior hire, or posts a relevant job, cross-referenced against existing team connections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$CRM Integrations$q$, $q$Sync network and signal data into Salesforce and HubSpot for reps to act on inside their existing workflow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$50+ Data Connectors$q$, $q$Pull network and relationship data from a wide range of connected sources to build a complete picture of team relationships.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Managed Go-to-Network Service$q$, $q$An optional dedicated assistant runs referral and network campaigns hands-off for teams that don't want to manage it internally.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Directly targets warm introductions and referrals, which typically convert and close faster than cold outreach$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Managed service option available for teams that don't want to run network campaigns themselves$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Native CRM integrations (Salesforce, HubSpot) keep reps in their existing workflow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Proof-of-concept trial available before committing to a paid plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Entry pricing starts at $1,000/month, higher than many self-serve sales tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Full pricing for larger teams or the managed service tier requires a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Value depends heavily on having an active investor/advisor/customer network to map in the first place$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$The company has pivoted its core product focus over time (from community-led growth to Go-to-Network), which is worth confirming is still current before purchase$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Did Commsor merge with Common Room?$q$, $q$No. Commsor and Common Room are separate companies that have never merged. They have historically operated in adjacent categories and have sometimes been listed as competitors or alternatives, which may explain the confusion, but no acquisition or merger between them has taken place.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$What does Commsor do today?$q$, $q$Commsor currently offers a 'Go-to-Network' product that maps a sales team's professional network to find warm introduction paths to target accounts and automates referral programs, a shift from its earlier community-led growth ('Community OS') positioning.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$How much does Commsor cost?$q$, $q$Commsor's Software plan starts at $1,000/month for 5+ seats and core network-mapping features. A Managed Service plan with a dedicated assistant running campaigns costs $6,500/month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Who is Commsor for?$q$, $q$It's built for B2B sales and revenue teams, particularly at venture-backed startups with active investor, advisor, and customer networks they want to convert into warm sales pipeline.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Does Commsor offer a trial?$q$, $q$Yes, a proof-of-concept trial is available to test the platform before subscribing.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Warm account entry for outbound sales$q$, $q$Find which investors, advisors, or existing customers can introduce a rep into a cold target account.$q$, $q$B2B sales development and account executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Partner and advisor referral programs$q$, $q$Run a structured referral program with deal registration and tracked payouts instead of informal, untracked referrals.$q$, $q$Revenue operations and partnerships teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Timely outreach on account signals$q$, $q$Get alerted when a target account raises funding or hires, and immediately see who on the team has an existing relationship there.$q$, $q$Venture-backed B2B startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Software$q$, $q$$1,000/month$q$, $q$Monthly$q$, NULL, $q$["5+ team seats","50+ data connectors","Unlimited personas and playbooks","Salesforce and HubSpot integrations","Dedicated customer success manager"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$Managed Service$q$, $q$$6,500/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Software","Dedicated Go-to-Network assistant","Campaign execution support","Hands-off network management"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Commsor is a go-to-market platform, founded in 2019 in New York by Jacob Peters and Mac Reddin, that has evolved from a general community-led growth ('Community OS') product into a more focused 'Go-to-Network' tool for B2B sales teams.$q$, $q$Rather than tracking generic community engagement, the current product maps a sales organization's collective professional network to find warm paths into target accounts through investors, advisors, partners, and existing customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Commsor's network mapping identifies who on a sales team already has a relationship with people at a target account, replacing cold outreach with warm introduction paths.$q$, $q$Referral program automation includes deal registration and tracked payouts for partners, advisors, or customers who make introductions, and signal-based alerts notify reps when a target account raises funding, hires, or posts a relevant job so they can act on timely, relevant openings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Commsor's Software plan starts at $1,000/month for 5+ seats, 50+ data connectors, and CRM integrations with Salesforce and HubSpot. A Managed Service plan at $6,500/month adds a dedicated assistant who runs referral and network campaigns on the customer's behalf.$q$, $q$A proof-of-concept trial is available before purchase, and pricing above the published tiers is handled through a sales conversation.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', $q$company-history$q$, $q$Company History and Relationship to Common Room$q$, 2, ARRAY[$q$Commsor was originally built as a community-led growth platform and raised a $50 million round in a period when community-led growth was a heavily funded category, reportedly reaching a valuation near $450 million.$q$, $q$Commsor and Common Room are separate companies that have never merged; despite similar-sounding names and overlapping categories, no acquisition between them has occurred. Common Room, unrelated to Commsor, is itself in the process of being acquired by Zoom as of July 2026.$q$]::text[], 3);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f22ba73c-1e88-4f7f-a98a-953343da5e1d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Live Market Pay Data$q$, $q$Continuously updated compensation data across Offers, Employees, Stock, Skills, and Frontline categories, built from 9M+ observations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Skills-Based Benchmarking$q$, $q$Benchmark pay against specific skills rather than only standardized job titles, suited to fast-moving fields like AI.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Grant-Level Equity Data$q$, $q$Benchmark stock and RSU grants alongside cash compensation for a complete total-rewards picture.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$HRIS/ATS/Equity Integrations$q$, $q$Connect to systems like Workday, Oracle, Greenhouse, Carta, and E*TRADE for automatic, continuous data sync.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Analyst Agent$q$, $q$An AI agent that analyzes market data and produces executive-ready answers to compensation questions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Partner Agent$q$, $q$Lets recruiting and HR stakeholders self-serve pay guidance for individual hiring and promotion decisions.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Continuous, live pay data instead of slow, periodic manual compensation surveys$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Skills-based benchmarking better reflects fast-changing roles in tech and life sciences$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Used by well-known large enterprises (Apple, NVIDIA, Tesla, Mastercard) across multiple industries$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$SOC 2 Type II certified and GDPR/CCPA compliant for enterprise data requirements$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Entry pricing starts at $35,000/year, out of reach for small and mid-sized businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Agents tier pricing is not public and requires a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Best value requires deep HRIS/ATS/equity system integration, adding implementation effort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Small vendor (~50-60 employees) relative to larger HR-tech platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$What does Compa do?$q$, $q$Compa is an AI-driven compensation intelligence platform that gives enterprise comp and recruiting teams live, continuously updated market pay data for offers, employees, and equity, instead of relying on periodic manual surveys.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$How much does Compa cost?$q$, $q$The Market Data tier starts at $35,000 per year, with multi-year discounts and pilot pricing available. The Agents tier is custom-priced through sales.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Who uses Compa?$q$, $q$Compa is used by enterprise compensation, total rewards, and recruiting teams, with reported customers including Apple, NVIDIA, Tesla, Mastercard, T-Mobile, Sanofi, Moderna, and Gilead Sciences.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$What systems does Compa integrate with?$q$, $q$Compa integrates with HR, ATS, and equity systems such as Workday, Oracle, Greenhouse, Carta, and E*TRADE to keep pay data continuously synced.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Real-time offer benchmarking$q$, $q$Check a candidate's offer against live market data before extending it, instead of relying on last year's survey data.$q$, $q$Enterprise recruiting and compensation teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Skills-based pay strategy$q$, $q$Benchmark fast-evolving technical and AI roles against skills rather than static job titles.$q$, $q$Technology and life sciences companies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Market Data$q$, $q$$35,000/year$q$, $q$Annual$q$, NULL, $q$["Live market pay data across Offers, Employees, Stock, Skills, Frontline categories","9M+ pay observations across 50+ countries","Integrations with HR, ATS, and equity systems"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$Agents$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Everything in Market Data","Analyst Agent for AI-assisted market analysis","Partner Agent for self-serve pay guidance"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Compa is an AI-driven compensation intelligence platform founded in 2020 by Charlie Franklin, Joe Malandruccolo, and Taylor Cone, headquartered in Irvine, California. It replaces traditional, periodic compensation surveys with continuous, live market pay data pulled directly from a company's HR, ATS, and equity systems.$q$, $q$The platform is aimed at enterprise compensation, total rewards, and recruiting teams that need to benchmark pay decisions in real time rather than against stale survey data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Compa's market data covers Offers, Employees, Stock, Skills, and Frontline pay categories, drawn from more than 9 million observations across 50+ countries, and supports skills-based benchmarking rather than relying solely on standardized job titles.$q$, $q$Two AI agents extend the core data product: an Analyst Agent that helps compensation teams analyze the market and produce executive-ready answers, and a Partner Agent that lets recruiting and HR stakeholders self-serve pay guidance for individual hiring decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Compa's Market Data tier starts at $35,000 per year, with multi-year discounts and pilot pricing available on request. The Agents tier, which adds the Analyst and Partner AI agents, is priced through a direct sales conversation rather than published rate cards.$q$, $q$This positions Compa firmly as an enterprise tool rather than a self-serve product for small teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ceff3588-dc14-4fe3-b8e5-e42a8227d73e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Inline AI Autocomplete$q$, $q$Get AI-generated text suggestions as you type on virtually any website, triggered by typing "//" or accepting inline completions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Text Rephrasing$q$, $q$Rewrite selected text to sound friendlier, more professional, shorter, or longer with one click.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Email Reply Generation$q$, $q$Generate a full email reply or expand a short note into a complete, formatted email.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Personalization$q$, $q$The system learns a user's writing style over time and suggests completions that match their personal voice.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Universal Browser Integration$q$, $q$Works across most websites and web apps without requiring platform-specific integrations.$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Free to use indefinitely for core autocomplete functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Works across virtually any website rather than being locked to one app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Lightweight and fast compared to switching to a full separate AI writing tool$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Backed by Y Combinator with a large reported user base (400,000+ users)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Limited to the Chrome browser, with no native desktop, iOS, or Android app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Narrower feature set than full AI writing platforms (no long-form generation, grammar scoring, or SEO tools)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Premium tier pricing is not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Company size and update cadence are not transparently published, making long-term support harder to verify$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Is Compose AI free?$q$, $q$Yes, the core autocomplete and rephrasing features are free to use indefinitely. A premium tier adds expanded personalization, though its price is not publicly listed.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$What browsers does Compose AI support?$q$, $q$Compose AI is distributed as a Chrome extension via the Chrome Web Store; it is not currently available as a native desktop or mobile app.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$How do you trigger Compose AI?$q$, $q$Type "//" followed by an instruction to generate text with AI, or simply keep typing and accept the inline suggestions it offers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Who is Compose AI for?$q$, $q$It's designed for professionals who type a high volume of email, messages, or web-based content and want faster, lighter-weight autocomplete than a full AI writing suite.$q$, 3, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Faster email replies$q$, $q$Generate a full email draft from a short phrase or set of bullet points instead of typing the whole message manually.$q$, $q$Sales, support, and customer-facing professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Consistent tone across web writing$q$, $q$Rephrase drafts to be friendlier, more professional, shorter, or longer directly inside whatever website you're writing in.$q$, $q$Individual professionals and content writers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Autocomplete across websites","\"//\" text generation trigger","Basic rephrasing tools","Email reply generation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$Premium$q$, $q$Not publicly disclosed$q$, $q$N/A$q$, NULL, $q$["Expanded personalization","Additional advanced writing features"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Compose AI is a free, Y Combinator-backed Chrome extension that adds AI-powered autocomplete to any website. Instead of a standalone editor, it works inline wherever a user types — in Gmail, Google Docs, LinkedIn, or internal web tools.$q$, $q$The product has been publicly available since around 2020 and reports being used by more than 10,000 teams and roughly 400,000 individual users.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core feature is inline autocomplete, triggered either by typing "//" followed by an instruction, or simply by accepting suggested completions as you type. A rephrasing tool can adjust selected text to sound friendlier, more professional, shorter, or longer.$q$, $q$An email-specific mode can generate a full draft reply from a short phrase, and a personalization layer learns an individual's writing style over time to make suggestions feel less generic.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Compose AI is free to use indefinitely for its core autocomplete and rephrasing features, with no credit card required. A premium tier adds expanded personalization and additional advanced features; the exact premium price is not disclosed on the public marketing site.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f2bcc6e-4367-4eee-be32-0ccfd23149e3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$All-in-One Contract Drafting$q$, $q$Draft contracts in a familiar Word/Google-Docs-style editor without switching tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Real-Time Collaboration$q$, $q$Collaborate on drafts in real time with both internal stakeholders and external counterparties.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Legally Binding E-Signature$q$, $q$Sign contracts electronically inside the same platform used for drafting and review, with unlimited free external signers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$AI Copilot for Contract Review$q$, $q$AI-assisted review and data extraction helps identify key clauses, obligations, and risk points faster.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Deadline & Renewal Reminders$q$, $q$Automated reminders for deadlines, renewals, and amendments help prevent contracts from silently lapsing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Approval Workflows & Clause Library$q$, $q$Business and Enterprise tiers add custom approval workflows, intake forms, and a reusable clause library.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$CRM & Storage Integrations$q$, $q$Connect Concord to Salesforce, HubSpot, Google Drive, Box, Dropbox, and Zapier for contract data flow across your stack.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Combines drafting, collaboration, e-signature, and tracking in a single system$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Unlimited free external viewers and guests means counterparties never need a paid account$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Flat per-tier pricing with no per-document or per-signature fees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$14-day free trial with full feature access before purchase$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Entry pricing starts at $499/month, higher than lightweight e-signature-only tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Advanced workflow and clause-library features are reserved for Business and Enterprise tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Slack integration is still in beta$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Best suited to SMB/mid-market teams; very large enterprises with complex legal ops may need deeper customization than the platform offers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$How much does Concord cost?$q$, $q$Concord's Essentials plan starts at $499/month billed annually for 5 users, with Business at $899/month and Enterprise at $1,299/month, each adding more workflow and integration features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Does Concord offer a free trial?$q$, $q$Yes, Concord offers a 14-day free trial with full access to paid features before requiring a subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Do external parties need to pay to sign a contract in Concord?$q$, $q$No, all Concord plans include unlimited free viewers and guests, so counterparties can review and sign without a paid seat.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Does Concord have an API?$q$, $q$Yes, an open API is available on the Enterprise plan for custom integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$What does Concord's AI Copilot do?$q$, $q$It assists with contract review and data extraction, helping teams identify key clauses, obligations, and risk points without manual line-by-line review.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$End-to-end contract lifecycle management$q$, $q$Draft, negotiate, sign, and track contracts in a single system instead of stitching together separate tools.$q$, $q$Legal and procurement teams at SMB/mid-market companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Sales contract turnaround$q$, $q$Speed up deal closing by drafting and sending contracts for e-signature directly from CRM-integrated workflows.$q$, $q$Sales operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Renewal and compliance tracking$q$, $q$Use automated deadline and renewal reminders to avoid missed contract expirations or auto-renewals.$q$, $q$Finance and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Essentials$q$, $q$$499/month$q$, $q$Annual (5 users included, +$49/user/month)$q$, NULL, $q$["AI Copilot for review and extraction","Unlimited e-signatures and documents","Collaboration tools","Deadline reminders","Amendment management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Business$q$, $q$$899/month$q$, $q$Annual (5 users included, +$69/user/month)$q$, NULL, $q$["Everything in Essentials","Intake forms and approval workflows","Custom roles and teams","Customized reporting","Salesforce, HubSpot, Google Drive, Box, Dropbox, Zapier integrations","Slack integration (beta)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$Enterprise$q$, $q$$1,299/month$q$, $q$Annual (5 users included, +$89/user/month)$q$, NULL, $q$["Everything in Business","Clause library","Subsidiary/multi-entity management","Bulk send","Open API","Custom branding","Volume discounts available"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Concord is a contract lifecycle management platform founded in 2014 and headquartered in Paris, France, with a U.S. office in Austin, Texas. It combines contract drafting, collaboration, e-signature, and post-signature management into a single system.$q$, $q$The company reports serving more than 1,500 SMB and mid-market organizations across North America and Europe, targeting legal, procurement, sales, and HR teams that want to manage the full contract lifecycle in one tool rather than separate point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Contracts can be drafted directly in Concord's Word- and Google-Docs-like editor, with real-time collaboration for both internal stakeholders and external counterparties, and legally binding e-signature built in.$q$, $q$An AI Copilot assists with contract review and data extraction, surfacing key clauses and obligations, while automated deadline, renewal, and amendment reminders help prevent contracts from silently lapsing.$q$, $q$Higher tiers add approval workflows, custom intake forms, a clause library, and integrations with Salesforce, HubSpot, Google Drive, Box, Dropbox, and Zapier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a0f2d3b-c073-4fa4-9c50-2b0847121c18', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Concord offers three annually billed tiers, each including 5 users: Essentials at $499/month, Business at $899/month, and Enterprise at $1,299/month, with additional users billed per seat. All plans include unlimited free external viewers and guests, so counterparties never need a paid seat to sign.$q$, $q$A 14-day free trial with full feature access is available, and there are no disclosed setup or onboarding fees.$q$]::text[], 2);
