-- Enrichment marathon batch: Colossyan, Comet, CommaFeed, Common Room, Commsor, Compa, Compose AI, Concord

-- ── Colossyan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Colossyan is an AI video generator that turns scripts into presenter-led training videos with lifelike AI avatars, multilingual narration, and built-in e-learning tools.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~100 employees$q$, company_size),
  headquarters = COALESCE($q$Budapest, Hungary (also offices in New York and London)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Colossyan: AI Avatar Video Generator for Training$q$, seo_title),
  seo_meta_description = COALESCE($q$Create AI avatar training videos from text with Colossyan. Multilingual dubbing, SCORM export, quizzes, and branching scenarios for L&D teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Colossyan, marketed as Colossyan Creator, is an AI video generation platform that converts written scripts and documents into presenter-led videos using photorealistic AI avatars, removing the need for cameras, actors, or studio production. It was founded in 2020 in Budapest, Hungary, by CEO Dominik Mate Kovacs after his frustration with the cost and slowness of traditional corporate video production. The company now operates from offices in Budapest, New York, and London with roughly 100 employees. As of early 2025, Colossyan reported around 35,000 business accounts and close to one million videos generated cumulatively, positioning it primarily as a tool for corporate learning and development (L&D), internal communications, and customer education rather than consumer or entertainment video. The core workflow lets a user type or paste a script, choose from a library of more than 160 AI avatars and 170+ voices (filterable by accent, tone, age, and emotion), and generate a narrated video with natural facial expressions, lip-sync, and gestures matched to the script. Avatar narration, on-screen text, and interactive elements can be localized together in a single workflow, with narration and translation available across dozens of languages depending on the avatar tier, and voice cloning supported in around 29 languages from a one-to-five-minute voice sample. What differentiates Colossyan from general-purpose AI video tools such as Synthesia or HeyGen is its emphasis on e-learning-specific functionality: built-in interactive quizzes, branching decision-tree scenarios, a Brand Kit for consistent logos/fonts/colors, and native SCORM export so finished videos can be uploaded directly into a corporate LMS and track completion and quiz scores. The product also includes AI image generation for slide backgrounds, a built-in screen recorder, and a document-to-video feature that can turn an existing PowerPoint deck or PDF into a video draft in under a minute. Colossyan uses a freemium pricing model. The Starter plan is free and includes a limited monthly allotment of avatar-narration minutes, a smaller avatar and voice library, a handful of interactive videos per month, and unlimited course creation, but does not include SCORM export. The Professional plan is $59/month on annual billing (roughly $30/month per additional editor seat) and adds more avatar minutes across the standard and premium (NEO2) avatar tiers, watermark-free MP4 downloads, SCORM export, AI image generation, and up to three editors. Enterprise pricing is quote-based and unlocks unlimited video minutes, unlimited SCORM exports, custom or branded studio avatars, SSO/SAML, data residency controls, and a dedicated customer success manager. An API is available for programmatic, large-scale video generation with the same feature set as the visual editor, including personalization variables for inserting viewer-specific data, and it connects to more than 5,000 apps via Zapier, though Colossyan lacks deep native integrations with CRM, help desk, or chat platforms beyond that. Typical use cases include compliance and safety training, employee onboarding, sales enablement content, and localized training for global workforces, since a single script can be re-rendered into many languages without re-filming. Reviewers commonly note the avatars can still look synthetic under close scrutiny and that per-minute usage caps on lower tiers can make high-volume use costly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e3f6fe0d-a0c1-42eb-8614-9f5fd7e21256';

