-- ── Comet ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Comet is Perplexity AI's agentic, Chromium-based web browser with a built-in AI assistant that can answer questions, summarize pages, and complete multi-step tasks.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$~350 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Comet by Perplexity: Free AI Agentic Web Browser$q$, seo_title),
  seo_meta_description = COALESCE($q$Comet is Perplexity's free AI browser with a built-in agent that browses, researches, and completes tasks for you on Windows, Mac, iOS, and Android.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Comet is an AI-native, Chromium-based web browser built by Perplexity AI, the answer-engine company founded in August 2022 by Aravind Srinivas, Denis Yarats, Johnny Ho, and Andy Konwinski, headquartered in San Francisco with roughly 350 employees and a valuation reported around $20 billion as of late 2025. Comet embeds an AI agent directly into the browser's sidebar rather than as a separate chat window: it knows which tab a user is on, retains context across a browsing session, and can take multi-step actions on a user's behalf, such as summarizing a page, comparing product reviews, drafting an email, or completing a multi-step research task across several tabs. Perplexity first released Comet on July 9, 2025, initially to a limited group of Perplexity Max subscribers paying $200/month, then made it free for everyone worldwide on Windows and macOS starting October 2, 2025. The company subsequently expanded platform coverage, launching Comet on Android in November 2025 and on iOS/iPadOS in March 2026, making it available across desktop and mobile. Perplexity has continued to invest heavily in the product, reportedly raising around $200 million specifically to grow Comet, which the company frames as the "front door" to an emerging agent-driven internet. Core capabilities include Perplexity's cited-answer search built into every page, a background assistant (for Max subscribers) that can handle multi-step tasks like booking or emailing without constant supervision, a native ad blocker, voice mode for hands-free queries on mobile, and, for Max subscribers, access to top-tier models including Claude Opus for more advanced agentic tasks. Perplexity also sells a standalone $5/month add-on called Comet Plus, which bundles AI-enhanced access to publisher news content, positioned as an alternative to services like Apple News. Because Comet is free at its core, its main competitors are other browsers rather than paid SaaS tools: Google Chrome, Microsoft Edge with Copilot, The Browser Company's Dia and Arc, and Opera's Neon are the closest comparisons, with Comet's differentiation being how deeply the AI agent is woven into everyday browsing rather than bolted on as an extension. Comet's agentic capabilities have also drawn significant security scrutiny. Independent researchers at Brave, LayerX, and Zenity Labs documented indirect prompt-injection attack vectors in 2025 and 2026 — including a technique nicknamed "CometJacking," where a single malicious link or a booby-trapped calendar invite could hijack the browser agent's session, and in one demonstrated case, steer it into an authenticated password manager to reveal or change stored credentials, or exfiltrate local files with no further user interaction. Perplexity has published its own security and privacy FAQ addressing some of these concerns and continues to patch reported vulnerabilities, but reviewers and security researchers generally caution that granting an AI agent broad access to logged-in sessions, email, and calendars introduces a materially different risk profile than traditional browsing, and that agentic browsers as a category are still maturing their security architecture.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd1e51b23-11d5-4a32-91ce-ccf878a2484a';

