-- ── CommaFeed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CommaFeed is a free, open-source RSS feed reader inspired by Google Reader, available as a free hosted instance or a self-hostable Java/React application.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CommaFeed: Free Open-Source RSS Reader$q$, seo_title),
  seo_meta_description = COALESCE($q$CommaFeed is a free, open-source Google Reader-style RSS reader. Self-host it with Docker or use the free hosted instance at commafeed.com.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CommaFeed is a free and open-source RSS feed reader modeled on the interface and organizational style of Google Reader, the popular feed reader Google discontinued in 2013. CommaFeed was first publicly released in May 2013, shortly after Google announced Google Reader's shutdown, filling the gap left for users who wanted a similar folder-and-subscription-based reading experience. The project is maintained on GitHub under the account "Athou" and has accumulated more than 3,600 stars and over 400 forks, indicating an active, established open-source community. Technically, CommaFeed's backend is written in Java on the Quarkus framework, chosen for fast startup time and low memory usage, while the frontend is built with React and TypeScript. It supports multiple database backends, including H2 for simple deployments and PostgreSQL, MySQL, or MariaDB for larger installations. The entire codebase is released under the Apache-2.0 license, meaning anyone can inspect, modify, self-host, or fork it without licensing fees. There are two primary ways to use CommaFeed. The first is the free public hosted instance at commafeed.com, which the project states carries no ads, no tracking, and does not sell or exploit user data — effectively a ready-to-use account for anyone who doesn't want to run their own server. The second is self-hosting, which is straightforward via Docker images published to Docker Hub, letting privacy-focused users, homelab enthusiasts, or organizations run their own private instance with full control over their data and infrastructure. Feature-wise, CommaFeed supports OPML import and export for moving subscriptions in and out of other readers, a REST API with Fever-API compatibility (so it can work with some third-party RSS client apps built for the discontinued Fever service), keyboard shortcuts for nearly all actions, four different layout options, light and dark themes, full mobile responsiveness, push notifications for new articles, support for right-to-left languages, a UI translated into more than 25 languages by community contributors, and the ability to apply custom CSS and JavaScript for deep personalization. Because it is a niche, community-maintained open-source tool rather than a funded startup, CommaFeed does not have a formal company, headquarters, or disclosed employee count, and it competes primarily with other self-hostable or privacy-oriented feed readers such as FreshRSS, Tiny Tiny RSS (TT-RSS), and Miniflux, as well as commercial hosted readers like Feedly and Inoreader. Its appeal is concentrated among developers, self-hosting enthusiasts, and users who specifically want a lightweight, ad-free, Google-Reader-like reading experience without vendor lock-in or a subscription fee, rather than users looking for AI summarization or heavy social/discovery features found in some modern feed readers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c3476f2a-8c51-4b81-9db1-f7d876d3be6b';

