-- ── Common Room ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Common Room is an AI-native customer intelligence platform that unifies buying signals from 30+ sources to help sales and marketing teams find and act on warm opportunities.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$2,500/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~180 employees$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Common Room: AI Customer Intelligence Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Common Room unifies buying signals from 30+ sources into one GTM platform with AI research agents. Zoom announced a deal to acquire it in July 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Common Room is an AI-native customer intelligence and go-to-market (GTM) platform founded in 2020 in Seattle, Washington, by Francis Luu, Linda Lian, Tom Kleinpeter, and Viraj Mody. The company has raised a total of roughly $104.9 million across funding rounds, including a Series B extension, and has grown to approximately 180 employees. In July 2026, Zoom announced a definitive agreement to acquire Common Room, describing the deal as bringing upstream buyer intelligence into Zoom's AI revenue platform and Zoom Revenue Accelerator product; financial terms were not disclosed, and the transaction was expected to close within weeks of the announcement, though as of the acquisition announcement Common Room continued operating as a distinct product. Common Room's core product captures buying and engagement signals from more than 30 data sources — including Slack, Discord, GitHub, Reddit, LinkedIn, Twitter/X, Stack Overflow, DEV, and Segment — and uses identity resolution to connect that activity to real people and accounts, giving sales, marketing, product, and community teams a unified view of who is engaging with a company across channels. The platform syncs enriched contact and signal data into Salesforce and HubSpot so reps can act on it inside their existing CRM workflow, and it includes AI agent features branded RoomieAI (for AI-assisted research and account summarization) and Prospector (for account and contact discovery), alongside unlimited configurable alerts, workflows, and audience segments. Common Room is priced as an enterprise SaaS product with three public tiers. The Essential plan costs $2,500/month billed annually and includes 5 seats, up to 100,000 tracked contacts, 5,000 monthly RoomieAI research credits, and 2,500 monthly Prospector credits, along with a shared customer success manager. The Advanced plan (15 seats, up to 250,000 contacts, 7,500 RoomieAI and Prospector credits each, dedicated CSM) and Enterprise plan (30 seats, up to 750,000 contacts, 10,000 RoomieAI credits, 15,000 Prospector credits, comprehensive integrations, dedicated CSM) are both custom-quoted. There is no free tier; prospective customers must engage with sales for anything beyond Essential. Common Room is positioned for B2B SaaS companies, particularly those with a developer, open-source, or community-driven go-to-market motion, where signals from GitHub stars, Slack community activity, or product usage can meaningfully predict sales opportunities before a lead ever fills out a form. It competes most directly with Commsor (a separate, unrelated company despite operating in an adjacent category), as well as with community and intent-data platforms like Orbit, Warmly, Endgame, and Clearbit/Breeze-style intent tools. The pending Zoom acquisition signals a broader industry trend of established communication and revenue platforms acquiring specialized buyer-intelligence startups to build end-to-end AI-driven revenue workflows rather than leaving customers to stitch together point solutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ba720441-8cc7-4c09-b643-008d959f36c9';

