-- ── Commsor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Commsor is a B2B go-to-market platform that maps sales teams' professional networks to surface warm introduction paths and automate referral programs.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$1,000/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Commsor: Warm Intro & Referral Platform for B2B Sales$q$, seo_title),
  seo_meta_description = COALESCE($q$Commsor maps your team's network to find warm intro paths to target accounts and automates referral programs with tracked payouts, from $1,000/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Commsor is a B2B go-to-market platform founded in 2019 in New York by Jacob Peters and Mac Reddin. The company originally built "Community OS," a community-led growth platform for tracking and operationalizing branded community engagement, and raised a $50 million round anchored by Atomico with participation from SignalFire, Slack Fund, 776, Felicis, and more than 150 individual angel investors, reportedly reaching a valuation near $450 million at the time, with roughly $68 million raised in total across its history. Since then, Commsor has narrowed its focus and rebranded around a product it calls "Go-to-Network": rather than tracking general community engagement, it maps a sales team's collective professional network — investors, advisors, partners, alumni, and existing customers — to surface warm introduction paths into target accounts, instead of relying on cold outreach. Core capabilities include network mapping to a target account through people a rep already knows, scalable referral-program automation with deal registration and tracked payouts, and signal-based alerts that notify reps when a target account experiences a newsworthy event, such as raising funding, making a senior hire, or posting a relevant job opening, cross-referenced against who on the sales team has an existing connection there. It's important to clarify Commsor's relationship to Common Room, a separate, similarly named company in an adjacent category: the two have never merged or been acquired by one another. They are, and have historically been, competing or adjacent companies — Common Room in AI-native customer/buyer intelligence (and, as of July 2026, in the process of being acquired by Zoom) and Commsor in network-based referral and warm-introduction tooling. Third-party research and comparison sites have sometimes listed the two alongside each other as alternatives in the community/GTM-intelligence space, which may be the source of confusion about a merger, but no such transaction has taken place. Commsor's current pricing has two published tiers: a Software plan at $1,000/month covering 5+ team seats, 50+ data connectors, unlimited personas and playbooks, and CRM integrations with Salesforce and HubSpot, plus a dedicated customer success manager; and a Managed Service plan at $6,500/month that adds a dedicated Go-to-Network assistant who runs campaign execution and hands-off network management on the customer's behalf. A proof-of-concept trial is available before committing to either plan. Commsor is aimed at B2B sales and revenue teams — particularly at venture-backed startups with active investor, advisor, and customer networks — who want to systematically convert "who you know" into pipeline rather than relying purely on outbound cold outreach or paid intent data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f22ba73c-1e88-4f7f-a98a-953343da5e1d';

