-- ── Compa ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Compa is an AI-driven compensation intelligence platform that gives enterprise comp and recruiting teams live, verified market pay data for offers and employees.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$35,000/year$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~50 employees$q$, company_size),
  headquarters = COALESCE($q$Irvine, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Compa: AI Compensation Intelligence Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Compa gives enterprise comp teams live, verified market pay data and AI agents for offers, equity, and skills-based benchmarking. Used by Apple, NVIDIA.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Compa is an AI-driven compensation intelligence platform for enterprise compensation, total rewards, and recruiting teams, founded in 2020 by Charlie Franklin (CEO), Joe Malandruccolo, and Taylor Cone. The company is based in Irvine, California, with additional offices in Newport Beach and Fountain Valley, California, and has around 50 to 60 employees. Compa has raised roughly $20 million in total funding, including a $10 million Series B round. Its core pitch is replacing traditional, slow, survey-based compensation benchmarking with continuous, live market data: the platform connects directly to a company's HR, HRIS, ATS, and equity systems (integrating with tools like Workday, Oracle, Greenhouse, Carta, and E*TRADE) so that pay data updates automatically rather than requiring teams to manually participate in periodic compensation surveys. Compa's market data spans five categories — Offers, Employees, Stock, Skills, and Frontline — and is built from more than 9 million pay observations across more than 50 countries and industries including technology, healthcare, retail, finance, professional services, and manufacturing. This lets comp teams benchmark not just against a job title, but against specific skills, which the company argues better reflects how compensation actually works in fast-moving fields like AI and life sciences, where roles and skill sets change faster than standardized job codes can keep up. Compa also offers grant-level equity compensation data, letting companies benchmark stock and RSU grants alongside cash compensation. In 2026, Compa's product messaging has shifted toward AI agents: an "Analyst Agent" that works alongside a company's compensation team to analyze market data and produce executive-ready answers to pay questions in seconds, and a "Partner Agent" that lets non-compensation stakeholders in recruiting and HR self-serve pay guidance for thousands of individual hiring or promotion decisions without looping in the core comp team for every request. The platform is SOC 2 Type II certified and compliant with GDPR and CCPA, reflecting its focus on serving large enterprises handling sensitive compensation data. Compa reports serving more than 100 customers, including well-known enterprises such as Apple, NVIDIA, Tesla, Mastercard, T-Mobile, Sanofi, Moderna, and Gilead Sciences, spanning technology and life sciences sectors where compensation decisions are high-stakes and need to reflect real-time market conditions. Pricing is enterprise-oriented and not aimed at small businesses: the Market Data tier starts at $35,000 per year, with multi-year discounts and pilot pricing available on request, while the newer Agents tier is priced through a direct sales conversation. As a relatively small, venture-backed company serving a specialized enterprise HR-tech niche, Compa is best understood as a focused compensation-intelligence vendor rather than a broad HR platform, competing with players like OpenComp, Pave, and Ravio in the compensation benchmarking space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ceff3588-dc14-4fe3-b8e5-e42a8227d73e';

