-- ── Compose AI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Compose AI is a free Chrome extension that adds AI-powered autocomplete and text generation to any website, helping users write emails and messages faster.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Compose AI: Free AI Writing Autocomplete Extension$q$, seo_title),
  seo_meta_description = COALESCE($q$Compose AI is a free Chrome extension that autocompletes your writing anywhere on the web, rephrases text, and drafts email replies using AI.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Compose AI is a browser-based AI writing assistant distributed as a free Chrome extension, backed by Y Combinator. Rather than being a standalone writing application, it embeds directly into the Chrome browser and adds inline AI autocomplete to whatever website or web app a user is typing in, such as Gmail, Google Docs, LinkedIn, or a company's internal support tool. Public sources differ slightly on the exact founding details and founding team, but the product is consistently described as a small, YC-backed startup that has been publicly available since around 2020. Its central feature is autocomplete: a user can type two forward slashes ("//") followed by a short instruction to generate text with AI, or simply keep typing and accept inline suggestions the extension offers based on context, similar to how code editors offer autocomplete. Beyond basic autocomplete, Compose AI includes a rephrasing tool that can adjust a selected passage of text to sound friendlier, more professional, shorter, or longer, and an email-specific feature that can generate a full draft reply from a short phrase or set of bullet points, or expand a short note into a complete, properly formatted email. A personalization layer is designed to learn an individual user's writing voice over time and suggest phrases and completions that increasingly match their own style rather than a generic AI tone. According to the company's own marketing site, Compose AI is used by more than 10,000 teams and roughly 400,000 individual users, and is positioned for professionals who send a high volume of email, sales and support messages, job descriptions, or social posts and want a lightweight way to reduce typing time (the company cites internal claims of cutting writing time by up to 40%) without switching to a separate, full-featured AI writing application. Pricing follows a straightforward freemium model: the core autocomplete and rephrasing functionality is free to use indefinitely with no credit card required, while a premium tier unlocks expanded personalization and additional advanced writing features; Compose AI's public marketing pages do not disclose the exact price of the premium tier. Because it is a Chrome extension rather than a standalone product, Compose AI's scope is intentionally narrow compared to full AI writing platforms like Grammarly, Jasper, or Copy.ai — it does not offer long-form content generation, grammar/style scoring, or SEO tooling, and it is currently limited to the Chrome browser rather than being available as a native desktop, iOS, or Android application. It's best understood as a focused productivity add-on for people who already spend most of their workday typing inside a browser and want faster completions without adopting a heavier AI writing suite.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1f2bcc6e-4367-4eee-be32-0ccfd23149e3';

