-- ── Concord ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Concord is a contract lifecycle management platform combining drafting, real-time collaboration, AI-assisted review, and e-signature in one system.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$499/month (billed annually, includes 5 users)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France (with a U.S. office in Austin, Texas)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Concord: Contract Management & CLM Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Concord is a CLM platform for contract drafting, AI-assisted review, e-signature, and approval workflows, used by 1,500+ SMB and mid-market companies.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Concord (also known as Concord Worldwide, or Concord CLM) is a contract lifecycle management (CLM) platform founded in 2014, reportedly by CEO Matt Lhoumeau together with Florian Parain, and headquartered in Paris, France, with a U.S. office in Austin, Texas. The company has raised approximately $38.7 million in funding from investors including CRV, Tenaya Capital, and Alven, and reports serving more than 1,500 small-to-mid-market organizations, generally in the 50-to-1,000-employee range, across North America and Europe. Concord's positioning is that it combines the full contract lifecycle into a single system rather than requiring teams to stitch together a separate word processor, e-signature tool, and spreadsheet-based contract tracker. Core functionality includes contract drafting in a Word- or Google-Docs-like editor, real-time internal and external collaboration on drafts, legally binding e-signature with unlimited free viewer and guest access, and automated deadline, renewal, and amendment reminders so contracts don't silently lapse. An AI Copilot feature assists with contract review and data extraction, helping legal and procurement teams quickly identify key clauses, obligations, and risk points across a document without manual line-by-line review. Concord's pricing is structured in three tiers, each billed annually and including five users, with additional users billed per seat per month. The Essentials plan is $499/month (additional users at $49/month each) and includes the AI Copilot, unlimited e-signatures and documents, collaboration tools, deadline reminders, and amendment management. The Business plan is $899/month (additional users at $69/month each) and adds intake forms, approval workflows, custom roles and teams, customized reporting, and integrations with Salesforce, HubSpot, Google Drive, Box, Dropbox, and Zapier, plus a Slack integration in beta. The Enterprise plan is $1,299/month (additional users at $89/month each) and adds a clause library, subsidiary and multi-entity contract management, bulk send capability, an open API, and custom branding, with volume discounts available on request. All plans include bank-level encryption and unlimited free external viewers/guests, meaning counterparties don't need a paid seat to review or sign a contract. A 14-day free trial with full feature access is available before committing to a paid plan, and there are no disclosed setup or onboarding fees. Concord competes in the broader CLM market alongside tools like Ironclad, DocuSign CLM, PandaDoc, and Juro, and it is generally positioned toward SMB and mid-market legal, procurement, sales, and HR teams that want an all-in-one contract system rather than an enterprise-only CLM built primarily for large legal departments.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0a0f2d3b-c073-4fa4-9c50-2b0847121c18';

